import React from 'react';
import { Box, Typography, Container, Button, Grid, Card, CardContent, useTheme } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import { Timeline, Business, Security, Verified } from '@mui/icons-material';

const features = [
  {
    icon: <Timeline sx={{ fontSize: 40 }} />,
    title: 'Truy xuất nguồn gốc',
    description: 'Theo dõi toàn bộ quá trình từ sản xuất đến tiêu thụ sản phẩm',
    color: 'primary',
  },
  {
    icon: <Business sx={{ fontSize: 40 }} />,
    title: 'Quản lý doanh nghiệp',
    description: 'Công cụ quản lý sản phẩm và chuỗi cung ứng cho doanh nghiệp',
    color: 'secondary',
  },
  {
    icon: <Verified sx={{ fontSize: 40 }} />,
    title: 'Chứng nhận chất lượng',
    description: 'Xác thực và chứng nhận chất lượng sản phẩm',
    color: 'success',
  },
  {
    icon: <Security sx={{ fontSize: 40 }} />,
    title: 'Bảo mật thông tin',
    description: 'Sử dụng blockchain để đảm bảo tính minh bạch và không thể giả mạo',
    color: 'info',
  },
];

const Home: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();

  const handleGetStarted = () => {
    navigate('/register');
  };

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f5f5f5', py: 4 }}>
      <Container maxWidth="lg">
        {/* Hero Section */}
        <Box sx={{ py: 8, textAlign: 'center' }}>
          <Typography variant="h2" component="h1" gutterBottom>
            Hệ thống truy xuất nguồn gốc thực phẩm
          </Typography>
          <Typography variant="h5" color="text.secondary" paragraph>
            Sử dụng công nghệ blockchain để đảm bảo tính minh bạch và an toàn cho chuỗi cung ứng thực phẩm
          </Typography>
          <Button 
            variant="contained" 
            color="primary" 
            size="large"
            onClick={handleGetStarted}
            sx={{ mt: 2 }}
          >
            Bắt đầu ngay
          </Button>
        </Box>

        {/* Features Section */}
        <Box sx={{ py: 8 }}>
          <Typography variant="h4" align="center" gutterBottom>
            Tính năng nổi bật
          </Typography>
          <Grid container spacing={4} sx={{ mt: 2 }}>
            {features.map((feature, index) => (
              <Grid item xs={12} md={6} key={index}>
                <Card
                  sx={{
                    height: '100%',
                    cursor: 'pointer',
                    transition: 'transform 0.2s',
                    '&:hover': {
                      transform: 'translateY(-4px)',
                    },
                  }}
                >
                  <CardContent>
                    <Box sx={{ mb: 2, color: theme.palette.primary.main }}>
                      {feature.icon}
                    </Box>
                    <Typography variant="h6" gutterBottom>
                      {feature.title}
                    </Typography>
                    <Typography color="text.secondary">
                      {feature.description}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Box>
      </Container>
    </Box>
  );
};

export default Home;
